10	void
11	matrix_squareroot_s(const PyArrayObject* ap_Am, float* restrict ret_data, int* isIllconditioned, int* isSingular, CBLAS_INT* sq_info, int* view_as_complex)
12	{
13	    float aa, bb, cc, dd, cs, sn;
14	    // Setting indicators to False.
15	    // isComplex is set to True if the square-root turns out to be complex-valued (if exists)
16	    // isIllconditioned is set to True if the solution of the Sylvester equation is ill-conditioned
17	    // isSingular is set to True if the input is exactly singular
18	    *view_as_complex = 0;
19	    *isIllconditioned = 0;
20	    *isSingular = 0;
21	    int isComplex = 0;
22	    int upcasted_to_complex = 0;
23	
24	    // --------------------------------------------------------------------
25	    // Input Array Attributes
26	    // --------------------------------------------------------------------
27	    float* restrict Am_data = (float*)PyArray_DATA(ap_Am);
28	    int ndim = PyArray_NDIM(ap_Am);              // Number of dimensions
29	    npy_intp* shape = PyArray_SHAPE(ap_Am);      // Array shape
30	    npy_intp n = shape[ndim - 1];                // Slice size
31	    npy_intp* restrict strides = PyArray_STRIDES(ap_Am);
32	    // Get the number of slices to traverse if more than one; np.prod(shape[:-2])
33	    npy_intp outer_size = 1;
34	    if (ndim > 2)
35	    {
36	        for (int i = 0; i < ndim - 2; i++) { outer_size *= shape[i];}
37	    }
38	
39	    // --------------------------------------------------------------------
40	    // Workspace computation and allocation
41	    // --------------------------------------------------------------------
42	    CBLAS_INT info = 0, sdim = 0, lwork = -1, intn = (CBLAS_INT)n;
43	    float tmp_float = 0.0f, one = 1.0f, zero = 0.0f;
44	    BLAS_FUNC(sgees)("V", "N", NULL, &intn, NULL, &intn, &sdim, NULL, NULL, NULL, &intn, &tmp_float, &lwork, NULL, &info);
45	    // Improbable to fail at lwork query but check anyway
46	    if (info != 0) { *sq_info = -100; return;}
47	    lwork = (CBLAS_INT)tmp_float;
48	    // 2n*n + 2n*n for data and vs for potentially converting to complex if needed
49	    // n + n for wr, wi (needed for gees calls)
50	    // lwork for work
51	    size_t buffer_size = 4*n*n + 2*n + lwork;
52	    float* restrict buffer = malloc(buffer_size*sizeof(float));
53	    if (buffer == NULL) { *sq_info = -101; return; }
54	
55	    // --------------------------------------------------------------------
56	    // Pointers to the variables inside the buffer for easy access
57	    // --------------------------------------------------------------------
58	
59	    // Since we already allocated n*2n for the input, we can use the first and
60	    // second n*n for C to F conversion when needed.
61	    float* restrict data = &buffer[0];
62	    float* restrict data2 = &buffer[n*n];
63	    float* restrict vs = &buffer[2*n*n];
64	    float* restrict wr = &buffer[4*n*n];
65	    float* restrict wi = &buffer[4*n*n + n];
66	    float* restrict work = &buffer[4*n*n + 2*n];
67	    // Cover the first 2n*n and vs area with a complex pointer just in case
68	    SCIPY_C* complex_data = &((SCIPY_C*)buffer)[0];
69	    SCIPY_C* complex_vs = &((SCIPY_C*)buffer)[n*n];
70	
71	
72	    /*====================================================================
73	    |                    MAIN nxn SLICE LOOP                             |
74	    ====================================================================*/
75	    for (npy_intp idx = 0; idx < outer_size; idx++) {
76	        /*------------------------------------------------------------------
77	        Copy the current slice into buffer in F-layout for LAPACK calls. Note
78	        that the input can be in C or F layout and not necessarily contiguous.
79	        Since the input is predominantly C contiguous, we copy the data in
80	        C-layout first and then transpose it to F-layout.
81	
82	        The output is always a C contiguous array hence we visit slices in
83	        C-order for easy insertion to the output array; by just offsetting
84	        idx*n*n * sizeof(dtype). For this reason, we  start the offset
85	        calculation from the inner-most outer dimension.
86	        ------------------------------------------------------------------*/
87	        npy_intp offset = 0;
88	        npy_intp temp_idx = idx;
89	        for (int i = ndim - 3; i >= 0; i--) {
90	            offset += (temp_idx % shape[i]) * strides[i];
91	            temp_idx /= shape[i];
92	        }
93	        float* restrict slice_ptr = (float*)(Am_data + (offset/sizeof(float)));
94	
95	        for (CBLAS_INT i = 0; i < n; i++) {
96	            for (CBLAS_INT j = 0; j < n; j++) {
97	                data2[i * n + j] = *(slice_ptr + (i*strides[ndim - 2]/sizeof(float)) + (j*strides[ndim - 1]/sizeof(float)));
98	            }
99	        }
100	        swap_cf_s(data2, data, n, n, n);
101	
102	        isComplex = 0;
103	        // ------------------------------------------------------------------------
104	        // Check if array is (quasi)upper triangular.
105	        // ------------------------------------------------------------------------
106	        int isSchur = isschurf(data, n);
107	
108	        if (!isSchur)
109	        {
110	            BLAS_FUNC(sgees)("V", "N", NULL, &intn, data, &intn, &sdim, wr, wi, vs, &intn, work, &lwork, NULL, &info);
111	            if (info != 0)
112	            {
113	                free(buffer);
114	                *sq_info = -102;
115	                return;
116	            }
117	        } else {
118	            // Manually get the eigenvalues with possible 2x2 blocks on the diagonal
119	            for (Py_ssize_t col = 0; col < n; col++)
120	            {
121	                if (col == n - 1)
122	                {
123	                    // Last column 1x1 block
124	                    wr[col] = data[col*n + col];
125	                    wi[col] = 0.0f;
126	                } else if (data[col*n + col + 1] == 0.0f) {
127	                    // Real eigenvalue
128	                    wr[col] = data[col*n + col];
129	                    wi[col] = 0.0f;
130	                } else {
131	                    // 2x2 block
132	                    aa = data[col*n + col];
133	                    bb = data[(col + 1)*n + col];
134	                    cc = data[col*n + col + 1];
135	                    dd = data[(col + 1)*n + col + 1];
136	                    BLAS_FUNC(slanv2)(&aa, &bb, &cc, &dd, &wr[col], &wi[col], &wr[col+1], &wi[col+1], &cs, &sn);
137	                    col++;
138	                }
139	            }
140	        }
141	
142	        // Check for singularity and negative eigenvalues on the real axis
143	        for (Py_ssize_t i = 0; i < n; i++)
144	        {
145	            if (wi[i] == 0.0f) {
146	                if (wr[i] < 0.0f) { isComplex = 1; }
147	                if (wr[i] == 0.0f) { *isSingular = 1; }
148	            }
149	        }
150	
151	        // Compute the square root of the Schur form
152	        if (isComplex)
153	        {
154	            // -- Convert real to complex
155	            // The squareroot is determined to be complex valued.
156	            // The data is already in F-layout so we need to insert a zero
157	            // between each float to make it complex-valued array with imaginary
158	            // part as zero. Same is true for the Schur vectors in vs.
159	
160	            // Hence data n*n will become 2n*n with the zebra pattern
161	            // [real, real, real, ...] --> [real, 0, real, 0, ...]
162	            // We start from the end of the 2n*n array and insert zeros.
163	            zebra_pattern_s(buffer, n*n);
164	            // If needed, do the same for the Schur vectors
165	            if (!isSchur) { zebra_pattern_s(vs, n*n); }
166	
167	            // Convert real schur form to complex schur form in float arithmetic
168	            for (Py_ssize_t col = 0; col < (n - 1); col++)
169	            {
170	                if (data[2*(col*n + col + 1)] == 0.0f)
171	                {
172	                    // Real eigenvalue
173	                    continue;
174	                } else {
175	                    // The only guarantee we have is c != 0, hence we use
176	                    // [lambda - d, c] eigenvector for triangularization as
177	                    // [b, \lambda - a] might become 0.
178	
179	                    // 2x2-block eigenvalues are still in wr and wi. So we can
180	                    // avoid complex arithmetic.
181	                    float u2 = data[2*(col*n + col + 1)];                       // c
182	                    float d_term = data[2*((col+1)*n + col + 1)];               // d
183	                    float mag = hypotf(hypotf(wr[col] - d_term, wi[col]), u2);  // ||[lambda - d, c]||
184	                    float u1re = (wr[col] - d_term) / mag;                      // (lambda - d).real / ||lambda - d||
185	                    float u1im = wi[col] / mag;                                 // (lambda - d).imag / ||lambda - d||
186	                    u2 /= mag;                                                  // c / ||lambda - d||
187	
188	                    // Apply conjugate from left
189	                    // [u1', u2] @ [temp1] = [temp1*u1' + temp2*u2]
190	                    // [-u2, u1]   [temp2]   [-temp1*u2 + temp2*u1]
191	                    for (Py_ssize_t i = col; i < n; i++)
192	                    {
193	                        float temp1 = data[2*i*n + 2*col];
194	                        float temp2 = data[2*i*n + 2*col + 2];
195	                        data[2*i*n + 2*col    ] =  u1re*temp1 + u2*temp2;
196	                        data[2*i*n + 2*col + 1] = -u1im*temp1;
197	                        data[2*i*n + 2*col + 2] = -u2*temp1   + u1re*temp2;
198	                        data[2*i*n + 2*col + 3] =  u1im*temp2;
199	                    }
200	
201	                    // Apply from right both to data and vs, temps are complex valued
202	                    // [temp1, temp2] @ [u1, -u2] = [temp1*u1 + temp2*u2, -temp1*u2 + temp2*u1']
203	                    //                  [u2, u1']
204	
205	                    // (x + yi) (w - zi) = (xw + yz) + (yw - xz)i
206	                    // (x + yi) (w + zi) = (xw - yz) + (yw + xz)i
207	                    for (Py_ssize_t i = 0; i <= col + 1; i++)
208	                    {
209	                        float temp1re = data[2*n*col       + 2*i];
210	                        float temp1im = data[2*n*col       + 2*i + 1];
211	                        float temp2re = data[2*n*(col + 1) + 2*i];
212	                        float temp2im = data[2*n*(col + 1) + 2*i + 1];
213	                        data[2*n*col       + 2*i    ] =  temp1re*u1re - temp1im*u1im + temp2re*u2;
214	                        data[2*n*col       + 2*i + 1] =  temp1re*u1im + temp1im*u1re + temp2im*u2;
215	                        data[2*n*(col + 1) + 2*i    ] = -temp1re*u2   + temp2re*u1re + temp2im*u1im;
216	                        data[2*n*(col + 1) + 2*i + 1] = -temp1im*u2   - temp2re*u1im + temp2im*u1re;
217	                    }
218	
219	                    // Clean up the noise, zero out the subdiagonal
220	                    data[2*n*col + 2*col + 2] = 0.0f;
221	                    data[2*n*col + 2*col + 3] = 0.0f;
222	
223	                    if (!isSchur)
224	                    {
225	                        for (Py_ssize_t i = 0; i < n; i++)
226	                        {
227	                            float temp1 = vs[2*n*col       + 2*i];
228	                            float temp2 = vs[2*n*(col + 1) + 2*i];
229	                            vs[2*n*col       + 2*i    ] =  u1re*temp1 + u2*temp2;
230	                            vs[2*n*col       + 2*i + 1] =  u1im*temp1;
231	                            vs[2*n*(col + 1) + 2*i    ] = -u2*temp1   + u1re*temp2;
232	                            vs[2*n*(col + 1) + 2*i + 1] = -u1im*temp2;
233	                        }
234	                    }
235	                    // Skip next column
236	                    col++;
237	                }
238	            }
239	
240	            // Compute the complex square root
241	            info = sqrtm_recursion_c(complex_data, n, n);
242	            // Unapply the Schur decomposition, use the return array current
243	            // slice as scratch space for the matrix multiplications
244	            if (!isSchur)
245	            {
246	                // ret_data = vs * data
247	                // data = ret_data * vs^H
248	                SCIPY_C c_one = CPLX_C(1.0f, 0.0f);
249	                SCIPY_C c_zero = CPLX_C(0.0f, 0.0f);
250	                BLAS_FUNC(cgemm)("N", "N", &intn, &intn, &intn, &c_one, complex_vs, &intn, complex_data, &intn, &c_zero, &((SCIPY_C*)ret_data)[idx*n*n], &intn);
251	                BLAS_FUNC(cgemm)("N", "C", &intn, &intn, &intn, &c_one, &((SCIPY_C*)ret_data)[idx*n*n], &intn, complex_vs, &intn, &c_zero, complex_data, &intn);
252	            }
253	
254	        } else {
255	            // Compute the square root
256	            info = sqrtm_recursion_s(data, n, n);
257	            if (!isSchur)
258	            {
259	                // Apply the Schur decomposition, use the return array, current
260	                // slice as scratch space for the matrix multiplication.
261	                npy_intp new_address = (upcasted_to_complex? 2*idx*n*n : idx*n*n);
262	                BLAS_FUNC(sgemm)("N", "N", &intn, &intn, &intn, &one, vs, &intn, data, &intn, &zero, &ret_data[new_address], &intn);
263	                BLAS_FUNC(sgemm)("N", "T", &intn, &intn, &intn, &one, &ret_data[new_address], &intn, vs, &intn, &zero, data, &intn);
264	            }
265	        }
266	
267	        // Set the isIllconditioned flag if the Sylvester solver failed
268	        if (info != 0) { *isIllconditioned = 1; }
269	        // Now that we have the result, if this is the first result with complex
270	        // values, we need to upcast the return array too hence it gets the zebra
271	        // pattern too.
272	        if (isComplex)
273	        {
274	            if (!upcasted_to_complex)
275	            {
276	                // Signal the caller to view the return array as complex and
277	                // avoid doing this multiple times.
278	                *view_as_complex = 1;
279	
280	                // Introduce zebra pattern until end of current slice, (idx+1)*n*n
281	                // by going backwards.
282	                zebra_pattern_s(ret_data, n*n*(idx + 1));
283	                // Avoid doing this multiple times
284	                upcasted_to_complex = 1;
285	            }
286	            // Copy the complex result to the return array in C layout
287	            swap_cf_c(complex_data, &((SCIPY_C*)ret_data)[idx*n*n], n, n, n);
288	        } else {
289	
290	            // Copy the real result to the return array in C layout somewhere
291	            // depending on whether the return array was upcasted to complex
292	            // previously.
293	            swap_cf_s(data, &ret_data[(upcasted_to_complex? 2*idx*n*n : idx*n*n)], n, n, n);
294	
295	            // If the return array was upcasted to complex previously, we
296	            // need to add the zebra pattern for the current real slice which
297	            // is now living at idx*(2*n*n).
298	            if (upcasted_to_complex) {
299	                zebra_pattern_s(&ret_data[idx*2*n*n], n*n);
300	            }
301	        }
302	    }
303	    /*====================================================================
304	    |                  END OF nxn SLICE LOOP                             |
305	    ====================================================================*/
306	    free(buffer);
307	    return;
308	}
309	
310	
311	void
312	matrix_squareroot_d(const PyArrayObject* ap_Am, double* restrict ret_data, int* isIllconditioned, int* isSingular, CBLAS_INT* sq_info, int* view_as_complex)
313	{
314	    double aa, bb, cc, dd, cs, sn;
315	    *view_as_complex = 0;
316	    *isIllconditioned = 0;
317	    *isSingular = 0;
318	    int isComplex = 0;
319	    int upcasted_to_complex = 0;
320	
321	    double* restrict Am_data = (double*)PyArray_DATA(ap_Am);
322	    int ndim = PyArray_NDIM(ap_Am);
323	    npy_intp* shape = PyArray_SHAPE(ap_Am);
324	    npy_intp n = shape[ndim - 1];
325	    npy_intp* restrict strides = PyArray_STRIDES(ap_Am);
326	
327	    npy_intp outer_size = 1;
328	    if (ndim > 2)
329	    {
330	        for (int i = 0; i < ndim - 2; i++) { outer_size *= shape[i];}
331	    }
332	    CBLAS_INT info = 0, sdim = 0, lwork = -1, intn = (CBLAS_INT)n;
333	    double tmp_float = 0.0, one = 1.0, zero = 0.0;
334	    BLAS_FUNC(dgees)("V", "N", NULL, &intn, NULL, &intn, &sdim, NULL, NULL, NULL, &intn, &tmp_float, &lwork, NULL, &info);
335	    if (info != 0) { *sq_info = -100; return; }
336	    lwork = (CBLAS_INT)tmp_float;
337	    size_t buffer_size = 4*n*n + 2*n + lwork;
338	    double* restrict buffer = malloc(buffer_size*sizeof(double));
339	    if (buffer == NULL) { *sq_info = -101; return; }
340	
341	    double* restrict data = &buffer[0];
342	    double* restrict data2 = &buffer[n*n];
343	    double* restrict vs = &buffer[2*n*n];
344	    double* restrict wr = &buffer[4*n*n];
345	    double* restrict wi = &buffer[4*n*n + n];
346	    double* restrict work = &buffer[4*n*n + 2*n];
347	    SCIPY_Z* complex_data = &((SCIPY_Z*)buffer)[0];
348	    SCIPY_Z* complex_vs = &((SCIPY_Z*)buffer)[n*n];
349	
350	    for (npy_intp idx = 0; idx < outer_size; idx++) {
351	        npy_intp offset = 0;
352	        npy_intp temp_idx = idx;
353	        for (int i = ndim - 3; i >= 0; i--) {
354	            offset += (temp_idx % shape[i]) * strides[i];
355	            temp_idx /= shape[i];
356	        }
357	        double* restrict slice_ptr = (double*)(Am_data + (offset/sizeof(double)));
358	        for (CBLAS_INT i = 0; i < n; i++) {
359	            for (CBLAS_INT j = 0; j < n; j++) {
360	                data2[i * n + j] = *(slice_ptr + (i*strides[ndim - 2]/sizeof(double)) + (j*strides[ndim - 1]/sizeof(double)));
361	            }
362	        }
363	        swap_cf_d(data2, data, n, n, n);
364	
365	        isComplex = 0;
366	        int isSchur = isschur(data, n);
367	
368	        if (!isSchur)
369	        {
370	            BLAS_FUNC(dgees)("V", "N", NULL, &intn, data, &intn, &sdim, wr, wi, vs, &intn, work, &lwork, NULL, &info);
371	            if (info != 0)
372	            {
373	                free(buffer);
374	                *sq_info = -102;
375	                return;
376	            }
377	        } else {
378	
379	            for (Py_ssize_t col = 0; col < n; col++)
380	            {
381	                if (col == n - 1)
382	                {
383	                    wr[col] = data[col*n + col];
384	                    wi[col] = 0.0;
385	                } else if (data[col*n + col + 1] == 0.0) {
386	                    wr[col] = data[col*n + col];
387	                    wi[col] = 0.0;
388	                } else {
389	                    aa = data[col*n + col];
390	                    bb = data[(col + 1)*n + col];
391	                    cc = data[col*n + col + 1];
392	                    dd = data[(col + 1)*n + col + 1];
393	                    BLAS_FUNC(dlanv2)(&aa, &bb, &cc, &dd, &wr[col], &wi[col], &wr[col+1], &wi[col+1], &cs, &sn);
394	                    col++;
395	                }
396	            }
397	        }
398	
399	        for (Py_ssize_t i = 0; i < n; i++)
400	        {
401	            if (wi[i] == 0.0) {
402	                if (wr[i] < 0.0) { isComplex = 1; }
403	                if (wr[i] == 0.0) { *isSingular = 1; }
404	            }
405	        }
406	
407	        if (isComplex)
408	        {
409	            zebra_pattern_d(buffer, n*n);
410	            if (!isSchur) { zebra_pattern_d(vs, n*n); }
411	
412	            for (Py_ssize_t col = 0; col < (n - 1); col++)
413	            {
414	                if (data[2*(col*n + col + 1)] == 0.0)
415	                {
416	                    continue;
417	                } else {
418	                    double u2 = data[2*(col*n + col + 1)];
419	                    double d_term = data[2*((col+1)*n + col + 1)];
420	                    double mag = hypot(hypot(wr[col] - d_term, wi[col]), u2);
421	                    double u1re = (wr[col] - d_term) / mag;
422	                    double u1im = wi[col] / mag;
423	                    u2 = u2 / mag;
424	
425	                    for (Py_ssize_t i = col; i < n; i++)
426	                    {
427	                        double temp1 = data[2*i*n + 2*col];
428	                        double temp2 = data[2*i*n + 2*col + 2];
429	                        data[2*i*n + 2*col    ] =  u1re*temp1 + u2*temp2;
430	                        data[2*i*n + 2*col + 1] = -u1im*temp1;
431	                        data[2*i*n + 2*col + 2] = -u2*temp1   + u1re*temp2;
432	                        data[2*i*n + 2*col + 3] =  u1im*temp2;
433	                    }
434	
435	                    for (Py_ssize_t i = 0; i <= col + 1; i++)
436	                    {
437	                        double temp1re = data[2*n*col       + 2*i];
438	                        double temp1im = data[2*n*col       + 2*i + 1];
439	                        double temp2re = data[2*n*(col + 1) + 2*i];
440	                        double temp2im = data[2*n*(col + 1) + 2*i + 1];
441	                        data[2*n*col       + 2*i    ] =  temp1re*u1re - temp1im*u1im + temp2re*u2;
442	                        data[2*n*col       + 2*i + 1] =  temp1re*u1im + temp1im*u1re + temp2im*u2;
443	                        data[2*n*(col + 1) + 2*i    ] = -temp1re*u2   + temp2re*u1re + temp2im*u1im;
444	                        data[2*n*(col + 1) + 2*i + 1] = -temp1im*u2   - temp2re*u1im + temp2im*u1re;
445	                    }
446	
447	                    data[2*n*col + 2*col + 2] = 0.0;
448	                    data[2*n*col + 2*col + 3] = 0.0;
449	
450	                    if (!isSchur)
451	                    {
452	                        for (Py_ssize_t i = 0; i < n; i++)
453	                        {
454	                            double temp1 = vs[2*n*col       + 2*i];
455	                            double temp2 = vs[2*n*(col + 1) + 2*i];
456	                            vs[2*n*col       + 2*i    ] =  u1re*temp1 + u2*temp2;
457	                            vs[2*n*col       + 2*i + 1] =  u1im*temp1;
458	                            vs[2*n*(col + 1) + 2*i    ] = -u2*temp1   + u1re*temp2;
459	                            vs[2*n*(col + 1) + 2*i + 1] = -u1im*temp2;
460	                        }
461	                    }
462	                    col++;
463	                }
464	            }
465	            info = sqrtm_recursion_z(complex_data, n, n);
466	
467	            if (!isSchur)
468	            {
469	                SCIPY_Z c_one = CPLX_Z(1.0, 0.0);
470	                SCIPY_Z c_zero = CPLX_Z(0.0, 0.0);
471	                BLAS_FUNC(zgemm)("N", "N", &intn, &intn, &intn, &c_one, complex_vs, &intn, complex_data, &intn, &c_zero, &((SCIPY_Z*)ret_data)[idx*n*n], &intn);
472	                BLAS_FUNC(zgemm)("N", "C", &intn, &intn, &intn, &c_one, &((SCIPY_Z*)ret_data)[idx*n*n], &intn, complex_vs, &intn, &c_zero, complex_data, &intn);
473	            }
474	        } else {
475	            info = sqrtm_recursion_d(data, n, n);
476	            if (!isSchur)
477	            {
478	                npy_intp new_address = (upcasted_to_complex? 2*idx*n*n : idx*n*n);
479	                BLAS_FUNC(dgemm)("N", "N", &intn, &intn, &intn, &one, vs, &intn, data, &intn, &zero, &ret_data[new_address], &intn);
480	                BLAS_FUNC(dgemm)("N", "T", &intn, &intn, &intn, &one, &ret_data[new_address], &intn, vs, &intn, &zero, data, &intn);
481	            }
482	        }
483	
484	        if (info != 0) { *isIllconditioned = 1; }
485	        if (isComplex)
486	        {
487	            if (!upcasted_to_complex)
488	            {
489	                *view_as_complex = 1;
490	                zebra_pattern_d(ret_data, n*n*(idx + 1));
491	                upcasted_to_complex = 1;
492	            }
493	            swap_cf_z(complex_data, &((SCIPY_Z*)ret_data)[idx*n*n], n, n, n);
494	        } else {
495	            swap_cf_d(data, &ret_data[(upcasted_to_complex? 2*idx*n*n : idx*n*n)], n, n, n);
496	            if (upcasted_to_complex) { zebra_pattern_d(&ret_data[2*idx*n*n], n*n); }
497	        }
498	    }
499	    free(buffer);
500	    return;
501	}
