504	void
505	matrix_squareroot_c(const PyArrayObject* ap_Am, SCIPY_C* restrict ret_data, int* isIllconditioned, int* isSingular, CBLAS_INT* sq_info, int* unused)
506	{
507	
508	    *isIllconditioned = 0;
509	    *isSingular = 0;
510	
511	    SCIPY_C* restrict Am_data = (SCIPY_C*)PyArray_DATA(ap_Am);
512	    int ndim = PyArray_NDIM(ap_Am);
513	    npy_intp* shape = PyArray_SHAPE(ap_Am);
514	    npy_intp n = shape[ndim - 1];
515	    npy_intp* restrict strides = PyArray_STRIDES(ap_Am);
516	
517	    npy_intp outer_size = 1;
518	    if (ndim > 2)
519	    {
520	        for (int i = 0; i < ndim - 2; i++) { outer_size *= shape[i];}
521	    }
522	    CBLAS_INT info = 0, sdim = 0, lwork = -1, intn = (CBLAS_INT)n;
523	    SCIPY_C tmp_float = CPLX_C(0.0f, 0.0f), cone = CPLX_C(1.0f, 0.0f), czero = CPLX_C(0.0f, 0.0f);
524	    BLAS_FUNC(cgees)("V", "N", NULL, &intn, NULL, &intn, &sdim, NULL, NULL, &intn, &tmp_float, &lwork, NULL, NULL, &info);
525	    if (info != 0) { *sq_info = -100; return; }
526	
527	    lwork = (CBLAS_INT)crealf(tmp_float);
528	    size_t buffer_size = 2*n*n + 2*n + lwork;
529	    SCIPY_C* buffer = malloc(buffer_size*sizeof(SCIPY_C));
530	    if (buffer == NULL) { *sq_info = -101; return; }
531	
532	
533	    SCIPY_C* restrict data = &buffer[0];
534	    SCIPY_C* restrict vs = &buffer[n*n];
535	    SCIPY_C* restrict w = &buffer[2*n*n];
536	    float* restrict rwork = (float*)(&buffer[2*n*n + n]);
537	    SCIPY_C* restrict work = &buffer[2*n*n + 2*n];
538	
539	    for (npy_intp idx = 0; idx < outer_size; idx++) {
540	        npy_intp offset = 0;
541	        npy_intp temp_idx = idx;
542	        for (int i = ndim - 3; i >= 0; i--) {
543	            offset += (temp_idx % shape[i]) * strides[i];
544	            temp_idx /= shape[i];
545	        }
546	        SCIPY_C* restrict slice_ptr = (SCIPY_C*)(Am_data + (offset/sizeof(SCIPY_C)));
547	        for (Py_ssize_t i = 0; i < n; i++) {
548	            for (Py_ssize_t j = 0; j < n; j++) {
549	                vs[i * n + j] = *(slice_ptr + (i*strides[ndim - 2]/sizeof(SCIPY_C)) + (j*strides[ndim - 1]/sizeof(SCIPY_C)));
550	            }
551	        }
552	
553	        swap_cf_c(vs, data, n, n, n);
554	
555	        // Check if array is upper triangular
556	        int isSchur = 1;
557	        for (Py_ssize_t i = 0; i < n - 1; i++)
558	        {
559	            for (Py_ssize_t j = i + 1; j < n; j++)
560	            {
561	                if ((crealf(data[i*n + j]) != 0.0f) || (cimagf(data[i*n + j]) != 0.0f))
562	                {
563	                    isSchur = 0;
564	                    break;
565	                }
566	            }
567	            if (!isSchur) { break; }
568	        }
569	
570	        if (!isSchur)
571	        {
572	            BLAS_FUNC(cgees)("V", "N", NULL, &intn, data, &intn, &sdim, w, vs, &intn, work, &lwork, rwork, NULL, &info);
573	            if (info != 0)
574	            {
575	                free(buffer);
576	                *sq_info = -102;
577	                return;
578	            }
579	        } else {
580	            for (Py_ssize_t col = 0; col < n; col++)
581	            {
582	                w[col] = data[col*n + col];
583	            }
584	        }
585	
586	        for (Py_ssize_t i = 0; i < n; i++)
587	        {
588	            if ((cimagf(w[i]) == 0.0f) && (crealf(w[i]) == 0.0f)) { *isSingular = 1; }
589	        }
590	
591	        info = sqrtm_recursion_c(data, n, n);
592	        if (!isSchur)
593	        {
594	            BLAS_FUNC(cgemm)("N", "N", &intn, &intn, &intn, &cone, vs, &intn, data, &intn, &czero, &ret_data[idx*n*n], &intn);
595	            BLAS_FUNC(cgemm)("N", "C", &intn, &intn, &intn, &cone, &ret_data[idx*n*n], &intn, vs, &intn, &czero, data, &intn);
596	        }
597	
598	        if (info != 0) { *isIllconditioned = 1; }
599	        swap_cf_c(data, &ret_data[idx*n*n], n, n, n);
600	    }
601	    free(buffer);
602	    return;
603	}
