708	/*
709	 * sqrtm_recursion_(s|d|c|z) are functions that compute the square root of a
710	 * Fortran-ordered Schur matrix by recursion.
711	 * For triangular Schur form arrays, the method described in [1] is used.
712	 * For real valued quasi-upper triangular arrays, the method described in [2]
713	 * is integrated into the method of [1].
714	 *
715	 * [1] : https://doi.org/10.1007/978-3-642-36803-5_12
716	 * [2] : https://doi.org/10.1016/0024-3795(87)90118-2
717	 *
718	 * Input:
719	 * T : Pointer to the Schur array in Fortran layout
720	 * bign : Overall leading dimension of the input array
721	 * n : Current recursion size of the partial array
722	 *
723	 * Output:
724	 * info: 0 if successful, 1 if the Sylvester solver returned nonzero info.
725	 *
726	 */
727	int
728	sqrtm_recursion_s(float* T, npy_intp bign, npy_intp n)
729	{
730	    int i, i1 = 0, i2 = 0, j;
731	    CBLAS_INT info = 0, halfn, otherhalfn, int1 = 1, intbign = (CBLAS_INT)bign;
732	    float scale = 0.0, a, b, c, d, alpha, theta, mu;
733	    if (n == 1)
734	    {
735	        // Scalar block
736	        T[0] = sqrtf(T[0]);
737	        return 0;
738	    } else if (n == 2) {
739	        a = T[0];
740	        c = T[1];
741	        b = T[bign];
742	        d = T[bign + 1];
743	        if (c == 0.0)
744	        {
745	            // Triangular 2x2 block
746	            if ((a == 0.0) && (d == 0.0) && (b == 0.0)) { return 0; }
747	            if ((a == 0.0) && (d == 0.0)) { T[bign] = INFINITY; return 0; }
748	            T[0] = sqrtf(a);
749	            T[bign + 1] = sqrtf(d);
750	            T[bign] = T[bign] / (T[0] + T[bign + 1]);
751	            return 0;
752	        } else {
753	            // Complex eigenvalues
754	            theta = a;            // since a == d
755	            mu = sqrtf(-b*c);     // since b*c < 0
756	            if ((theta == 0.0) && (mu == 0.0)) { return 0; }
757	            if (theta > 0.0)
758	            {
759	                alpha = sqrtf((theta + hypotf(theta, mu)) / 2);
760	            } else {
761	                alpha = mu / sqrtf(2 * (-theta + hypotf(theta, mu)));
762	            }
763	            T[0] = alpha;
764	            T[1] = T[1] / (2*alpha);
765	            T[bign] = T[bign] / (2*alpha);
766	            T[bign + 1] = alpha;
767	            return 0;
768	        }
769	    } else {
770	        // Recursion
771	        halfn = (CBLAS_INT)(n / 2);
772	        // Don't split the 2x2 block, check if the entry under separation is zero
773	        if (T[(halfn-1)*bign + halfn] != 0.0) { halfn++; }
774	        otherhalfn = (CBLAS_INT)(n - halfn);
775	
776	        // Top left block
777	        i1 = sqrtm_recursion_s(T, bign, halfn);
778	        // Bottom right block
779	        i2 = sqrtm_recursion_s(&T[halfn*(bign + 1)], bign, otherhalfn);
780	
781	        // When n == 3, the Sylvester equation is 1x2 or 2x1. If both
782	        // sides have a zero diagonal, strsyl_ produces garbage instead
783	        // of inf. Detect this and set INFINITY so it propagates.
784	        int sylvester12 = (n == 3) && (halfn == 1);
785	        int sylvester21 = (n == 3) && (halfn == 2);
786	        if (sylvester12 && (T[0] == 0.0f) && ((T[intbign + 1] == 0.0f) || (T[2*(intbign + 1)] == 0.0f))) {
787	            T[intbign] = INFINITY;
788	            T[2*intbign] = INFINITY;
789	            info = 1;
790	        } else if (sylvester21 && (T[2*(intbign + 1)] == 0.0f) && ((T[0] == 0.0f) || (T[intbign + 1] == 0.0f))) {
791	            T[2*intbign] = INFINITY;
792	            T[2*intbign + 1] = INFINITY;
793	            info = 1;
794	        } else {
795	            BLAS_FUNC(strsyl)("N", "N", &int1, &halfn, &otherhalfn, T, &intbign, &T[halfn*(intbign + 1)], &intbign, &T[halfn*intbign], &intbign, &scale, &info);
796	            if (scale != 1.0)
797	            {
798	                for (i = 0; i < otherhalfn; i++)
799	                {
800	                    for (j = 0; j < halfn; j++)
801	                    {
802	                        T[(halfn + i)*bign + j] *= scale;
803	                    }
804	                }
805	            }
806	        }
807	    }
808	    // Propagate the Sylvester solver info up the recursion stack
809	    if (i1 || i2 || info)
810	    {
811	        return 1;
812	    } else {
813	        return 0;
814	    }
815	}
