869	        // Bottom right block
870	        i2 = sqrtm_recursion_d(&T[halfn*(bign + 1)], bign, otherhalfn);
871	
872	        // When n == 3, the Sylvester equation is 1x2 or 2x1. If both
873	        // sides have a zero diagonal, dtrsyl_ produces garbage instead
874	        // of inf. Detect this and set INFINITY so it propagates.
