887	            if (scale != 1.0)
888	            {
889	                for (i = 0; i < otherhalfn; i++)
890	                {
891	                    for (j = 0; j < halfn; j++)
892	                    {
893	                        T[(halfn + i)*bign + j] *= scale;
894	                    }
895	                }
896	            }
897	        }
898	    }
899	    // Propagate the Sylvester solver info up the recursion stack
900	    if (i1 || i2 || info)
901	    {
902	        return 1;
903	    } else {
904	        return 0;
905	    }
