        return 1;
    } else {
        return 0;
    }
}


int
sqrtm_recursion_c(SCIPY_C* T, npy_intp bign, npy_intp n)
{
    int i, i1 = 0, i2 = 0, j;
    CBLAS_INT info = 0, halfn, otherhalfn, int1 = 1, intbign = (CBLAS_INT)bign;
    float scale = 0.0;
    if (n == 1)
    {
        // Scalar block
        T[0] = csqrtf(T[0]);
        return 0;
    } else if (n == 2) {
        // 2x2 upper triangular special case

        // Check if the 2x2 block is exactly 0.0 and if so do nothing.
        if ((cabsf(T[0]) == 0.0) && (cabsf(T[bign + 1]) == 0.0) && (cabsf(T[bign]) == 0.0)) { return 0; }

        T[0] = csqrtf(T[0]);
        // n + 1 is the next diagonal from T[0]
        T[bign + 1] = csqrtf(T[bign + 1]);
#if defined(_MSC_VER)
        // MSVC does not support complex division
        SCIPY_C tt = CPLX_C(crealf(T[0]) + crealf(T[bign + 1]), cimagf(T[0]) + cimagf(T[bign + 1]));
        float cc = cabsf(tt);
        T[bign] = _FCmulcr(_FCmulcc(T[bign], conjf(tt)), 1 / (cc*cc));
#else
        T[bign] = T[bign] / (T[0] + T[bign + 1]);
#endif
        return 0;
    } else {
        halfn = (CBLAS_INT)(n / 2);
        otherhalfn = (CBLAS_INT)(n - halfn);
        SCIPY_C* T11 = T;
        SCIPY_C* T22 = &T[halfn*(bign + 1)];
        SCIPY_C* T12 = &T[halfn*bign];
        i1 = sqrtm_recursion_c(T11, bign, halfn);
        i2 = sqrtm_recursion_c(T22, bign, otherhalfn);

        // When n == 3, the Sylvester equation is 1x2 (complex Schur has
        // no 2x2 blocks so halfn is always 1). If both sides have a zero
        // diagonal, ctrsyl_ produces garbage. Set INFINITY to propagate.
        if ((n == 3) && (cabsf(T11[0]) == 0.0f) && ((cabsf(T22[0]) == 0.0f) || (cabsf(T22[intbign + 1]) == 0.0f))) {
            SCIPY_C cinf = CPLX_C(INFINITY, 0.0f);
            T12[0] = cinf;
            T12[intbign] = cinf;
            info = 1;
        } else {
            BLAS_FUNC(ctrsyl)("N", "N", &int1, &halfn, &otherhalfn, T11, &intbign, T22, &intbign, T12, &intbign, &scale, &info);
            if (scale != 1.0)
            {
                for (i = 0; i < otherhalfn; i++)
                {
                    for (j = 0; j < halfn; j++)
                    {
#if defined(_MSC_VER)
                        T[(halfn + i)*bign + j] = _FCmulcr(T[(halfn + i)*bign + j], scale);
#else
                        T[(halfn + i)*bign + j] *= scale;
#endif
                    }
                }
            }
        }
    }
    // Propagate the Sylvester solver info up the recursion stack
    if (i1 || i2 || info)
    {
        return 1;
    } else {
        return 0;
    }
}


int
sqrtm_recursion_z(SCIPY_Z* T, npy_intp bign, npy_intp n)
{
    int i, i1 = 0, i2 = 0, j;
    CBLAS_INT info = 0, halfn, otherhalfn, int1 = 1, intbign = (CBLAS_INT)bign;
